-- Seed the corrected substance catalog (265 substances). ADR-038.
-- Idempotent: upserts by name, then removes any leftover non-catalog substance that
-- nothing references (so a fresh DB / PROD ends with exactly this catalog, and on QA
-- the still-referenced legacy rows survive for the one-off reconcile script). Needs
-- 'cfu' in substance_unit (migration 0013) for the probiotic rows.

on conflict (name) do update set
  substance_type = excluded.substance_type,
  canonical_unit = excluded.canonical_unit,
  aliases        = excluded.aliases;

-- Drop legacy substances not in the catalog that nothing points at. On a fresh DB this
-- clears the original 0002 seed; on QA (all legacy rows referenced) it deletes nothing.
delete from substance
 where name not in ('Bicarbonate', 'Chloride', 'Magnesium Citrate', 'Magnesium Glycinate', 'Potassium', 'Potassium Citrate', 'Sodium', 'Sodium Chloride', 'Energy', 'Added Sugars', 'Alpha-Linolenic Acid', 'Arachidonic Acid', 'Beta-Glucan', 'Capric Acid', 'Caprylic Acid', 'Carbohydrate', 'Casein', 'Cellulose', 'Cholesterol', 'Collagen', 'Conjugated Linoleic Acid', 'Dietary Fiber', 'Docosahexaenoic Acid', 'Eicosapentaenoic Acid', 'Fat', 'Fructooligosaccharides', 'Fructose', 'Galactooligosaccharides', 'Galactose', 'Gamma-Linolenic Acid', 'Glucose', 'Guar Gum', 'Insoluble Fiber', 'Inulin', 'Lactose', 'Linoleic Acid', 'Maltose', 'Medium-Chain Triglycerides', 'Monounsaturated Fat', 'Oleic Acid', 'Omega-3 Fatty Acids', 'Omega-6 Fatty Acids', 'Pectin', 'Polyunsaturated Fat', 'Protein', 'Psyllium Husk', 'Resistant Starch', 'Saturated Fat', 'Soluble Fiber', 'Starch', 'Sucrose', 'Sugar', 'Trans Fat', 'Whey Protein Isolate', 'Xanthan Gum', 'Amlodipine', 'Amoxicillin', 'Aspirin', 'Atomoxetine', 'Atorvastatin', 'Azithromycin', 'Bupropion', 'Cetirizine', 'Dexamfetamine', 'Diclofenac', 'Diphenhydramine', 'Fluoxetine', 'Ibuprofen', 'Levothyroxine', 'Lisdexamfetamine', 'Lisinopril', 'Loperamide', 'Loratadine', 'Metformin', 'Methylphenidate', 'Metoprolol', 'Modafinil', 'Naproxen', 'Omeprazole', 'Paracetamol', 'Prednisone', 'Pseudoephedrine', 'Salbutamol', 'Sertraline', 'Boron', 'Calcium', 'Chromium', 'Copper', 'Fluoride', 'Iodine', 'Iron', 'Magnesium', 'Manganese', 'Molybdenum', 'Phosphorus', 'Selenium', 'Silicon', 'Zinc', 'Zinc Picolinate', 'Acesulfame K', 'Acetic Acid', 'Allium Sativum', 'Aspartame', 'Bacopa Monnieri', 'Beetroot Extract', 'Bifidobacterium Bifidum', 'Bifidobacterium Lactis', 'Bifidobacterium Longum', 'Camellia Sinensis', 'Cinnamon Extract', 'Citric Acid', 'Cranberry Extract', 'Curcuma Longa', 'Echinacea Purpurea', 'Erythritol', 'Ginkgo Biloba', 'Grape Seed Extract', 'Griffonia Simplicifolia', 'Humulus Lupulus', 'Hypericum Perforatum', 'Lactic Acid', 'Lactobacillus Aci